  const base = sumBasePremiums(items);
  const withSurcharge = Math.ceil(base * (1 + FIRST_INSURANCE_SURCHARGE));
  return withSurcharge + PROCESSING_FEE;
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  return { results: [{ premium: quotePremium(items) }] };
};

