const PROCESSING_FEE = 5;
const FIRST_INSURANCE_PERCENT = 110; // 100% + 10% first-insurance surcharge

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];

const sumBasePremiums = (items: any[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const applyPercent = (amount: number, percent: number): number =>
  Math.ceil((amount * percent) / 100);

const quotePremium = (items: any[]): number => {
  const base = sumBasePremiums(items);
  const withSurcharge = applyPercent(base, FIRST_INSURANCE_PERCENT);
  return withSurcharge + PROCESSING_FEE;
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  return { results: [{ premium: quotePremium(items) }] };
};

